'use client';

import { useState } from 'react';
import { motion, useMotionValue, useTransform } from 'framer-motion';
import { ArrowUpRight, ShieldCheck, ClockCounterClockwise, Image as ImageIcon } from '@phosphor-icons/react';

interface Product {
  id: string;
  name: string;
  price: number;
  description: string;
  warranty_days: number;
  max_claim_limit: number;
  thumbnail_url?: string;
}

export default function ProductCard({ product }: { product: Product }) {
  const [imgError, setImgError] = useState(false);
  // Magnetic button physics
  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const textX = useTransform(x, (latest) => latest * 0.5);
  const textY = useTransform(y, (latest) => latest * 0.5);

  const handleMouseMove = (e: React.MouseEvent<HTMLButtonElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    x.set(e.clientX - centerX);
    y.set(e.clientY - centerY);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  return (
    <motion.div 
      layout
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-50px" }}
      transition={{ type: "spring", stiffness: 100, damping: 20 }}
      className="group relative h-full"
    >
      {/* Outer Shell (Double-Bezel) */}
      <div className="h-full rounded-[2.5rem] bg-[var(--color-surface-card)] ring-1 ring-[var(--color-border-soft)] p-2 transition-all duration-700 ease-[cubic-bezier(0.32,0.72,0,1)] hover:bg-black/[0.02]">
        
        {/* Inner Core */}
        <div className="relative flex flex-col h-full rounded-[calc(2.5rem-0.5rem)] bg-[var(--color-surface-core)] p-8 shadow-[0_20px_40px_-15px_rgba(0,0,0,0.05)] border border-[var(--color-border-soft)] z-10 overflow-hidden">
          
          {/* Subtle inner highlight */}
          <div className="absolute inset-0 rounded-[calc(2.5rem-0.5rem)] pointer-events-none shadow-[inset_0_1px_1px_rgba(255,255,255,0.8)]" />

          {/* Thumbnail Image */}
          {product.thumbnail_url && (
            <div className="relative w-full aspect-video mb-6 rounded-2xl overflow-hidden z-20 flex-shrink-0 bg-[var(--color-surface-bg)] ring-1 ring-[var(--color-border-soft)]">
              {!imgError ? (
                <img 
                  src={product.thumbnail_url} 
                  alt={product.name} 
                  className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                  onError={() => setImgError(true)}
                />
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center bg-gradient-to-br from-[#effafd] to-[#d4f3f9] text-[var(--color-text-muted)]">
                  <ImageIcon size={32} weight="duotone" className="mb-2 opacity-50" />
                  <span className="text-xs font-medium opacity-70">Image not found</span>
                </div>
              )}
            </div>
          )}

          {/* Header */}
          <div className="mb-6 relative z-20">
            <h3 className="text-2xl font-bold tracking-tight text-[var(--color-text-primary)] mb-2 group-hover:text-[var(--color-action-hover)] transition-colors duration-500">
              {product.name}
            </h3>
            <p className="text-[var(--color-text-muted)] leading-relaxed text-sm h-14 overflow-hidden line-clamp-2">
              {product.description || 'Premium digital product with extended capabilities.'}
            </p>
          </div>

          {/* Pricing */}
          <div className="mb-8 relative z-20">
            <span className="text-4xl font-black tracking-tighter text-[var(--color-text-primary)]">
              Rp {product.price.toLocaleString('id-ID')}
            </span>
          </div>

          {/* Meta Info (Specs) */}
          <div className="flex flex-col gap-3 mb-10 flex-grow relative z-20">
            <div className="flex items-center gap-3 text-sm font-medium text-[var(--color-text-secondary)]">
              <div className="w-8 h-8 rounded-full bg-[var(--color-border-soft)] flex items-center justify-center shrink-0">
                <ShieldCheck size={16} className="text-[#00b4d8]" />
              </div>
              <span>{product.warranty_days} Days Warranty</span>
            </div>
            <div className="flex items-center gap-3 text-sm font-medium text-[var(--color-text-secondary)]">
              <div className="w-8 h-8 rounded-full bg-[var(--color-border-soft)] flex items-center justify-center shrink-0">
                <ClockCounterClockwise size={16} className="text-[#00b4d8]" />
              </div>
              <span>Max {product.max_claim_limit}x Claims</span>
            </div>
          </div>

          {/* Action Button */}
          <form action="/api/checkout" method="POST" className="mt-auto relative z-20">
            <input type="hidden" name="productId" value={product.id} />
            <motion.button
              type="submit"
              onMouseMove={handleMouseMove}
              onMouseLeave={handleMouseLeave}
              whileTap={{ scale: 0.96 }}
              className="relative flex items-center justify-between w-full rounded-full bg-[var(--color-action-primary)] hover:bg-[var(--color-action-hover)] text-[var(--color-surface-bg)] px-6 py-4 font-semibold overflow-hidden group/btn transition-colors duration-300"
            >
              <motion.span style={{ x: textX, y: textY }} className="z-10 pointer-events-none">
                Purchase Now
              </motion.span>
              <motion.span 
                style={{ x: textX, y: textY }}
                className="z-10 flex h-8 w-8 items-center justify-center rounded-full bg-black/20 pointer-events-none transition-transform group-hover/btn:translate-x-1 group-hover/btn:-translate-y-[1px]"
              >
                <ArrowUpRight weight="bold" size={16} />
              </motion.span>
            </motion.button>
          </form>

        </div>
      </div>
    </motion.div>
  );
}
